unitsize(0.15inch);
pair A,B,C,D,F;
A = (0,0);
B= (12,0);
C = (12,15);
D = (0,6);
F = (12,6);
draw(A--B--C--D--A);
draw(D--F,dashed);
label("$12$",B/2,S);
label("$12$",(D+F)/2,S);
label("$6$",D/2,W);
label("$6$",(F+B)/2,E);
label("$9$",(F+C)/2,E);
[/asy]


